import React from 'react';
import clsx from 'clsx';
import { UploadCardFile, UploadPictureFile, UploadSimpleTextFile, UploadTextFile } from '../uploadFile';
import { useUploadContext, useUploadContextSelector } from '../hooks/UploadContext';
import { Popover } from '../../popover';
import { Space } from '../../space';
import type { UploadListProps } from './interface';
import type { UploadFile } from '../uploadFile/interface';

// UploadCardFileList
export interface UploadCardFileListProps extends UploadListProps {
  /**
   * 自定义列表项, 可用来绑定事件回调，自定义 icon 等
   * @defaultValue (file: UploadFile) => <UploadCardFile file={file} />
   */
  itemRenderer?: UploadListProps['itemRenderer'];
}
const defaultCardItemRenderer = (file: UploadFile) => <UploadCardFile file={file} />;

export const UploadCardFileList = (props: UploadListProps) => {
  const { itemRenderer = defaultCardItemRenderer, ...spaceProps } = props;

  const fileList = useUploadContextSelector(ctx => ctx.fileList);
  return (
    <Space
      inline={false}
      direction="horizontal"
      // eslint-disable-next-line @typescript-eslint/no-magic-numbers
      size={[40, 16]}
      wrap
      align="start"
      {...spaceProps}
      itemKey={index => fileList[index].uid || index}
    >
      {fileList.map(file => (
        <React.Fragment key={file.uid}>{itemRenderer(file)}</React.Fragment>
      ))}
    </Space>
  );
};

